create table admin_users(id bigint not null auto_increment primary key,username varchar(64) not null unique,password varchar(255) not null,role varchar(32) not null,enabled boolean not null default true) engine=InnoDB default charset=utf8mb4 collate=utf8mb4_unicode_ci;
create table products(id bigint not null auto_increment primary key,title varchar(255) not null,content text,price decimal(14,2),image_url varchar(500),status varchar(32),sort_order int default 0,index idx_products_status(status)) engine=InnoDB default charset=utf8mb4 collate=utf8mb4_unicode_ci;
create table news_articles(id bigint not null auto_increment primary key,title varchar(255) not null,content text,image_url varchar(500),status varchar(32),published_at datetime,index idx_news_status(status)) engine=InnoDB default charset=utf8mb4 collate=utf8mb4_unicode_ci;
create table slides(id bigint not null auto_increment primary key,title varchar(255) not null,subtitle varchar(255),image_url varchar(500),link_url varchar(500),status varchar(32),sort_order int default 0) engine=InnoDB default charset=utf8mb4 collate=utf8mb4_unicode_ci;
create table bookings(id bigint not null auto_increment primary key,name varchar(255) not null,phone varchar(64) not null,city varchar(128),district varchar(128),status varchar(32),created_at datetime not null default current_timestamp,index idx_bookings_created_at(created_at)) engine=InnoDB default charset=utf8mb4 collate=utf8mb4_unicode_ci;
